def calculate_shipping(weight_kg: float, distance_km: float) -> float:
    base = 2.50
    weight_cost = weight_kg * 0.75
    distance_cost = (distance_km / 100) * 1.20
    if distance_km > 500:
        distance_cost *= 0.85
    return round(base + weight_cost + distance_cost, 2)

