class TextProcessor:
    def __init__(self, text):
        self.text = text
        self._words = None

    def word_count(self):
        return len(self.get_words())

    def get_words(self):
        if self._words is None:
            self._words = self.text.lower().split()
        return self._words

    def most_common(self, n):
        from collections import Counter
        return Counter(self.get_words()).most_common(n)

